const hoy = new Date();
const ayer = new Date(hoy);
ayer.setDate(ayer.getDate() - 1);

if (ayer.getDay() === 0) ayer.setDate(ayer.getDate() - 2);
if (ayer.getDay() === 6) ayer.setDate(ayer.getDate() - 1);

const yyyy = ayer.getFullYear();
const mm = String(ayer.getMonth() + 1).padStart(2, '0');
const dd = String(ayer.getDate()).padStart(2, '0');
const fecha = `${yyyy}${mm}${dd}`;

const staticData = $getWorkflowStaticData('global');

if (staticData.ultimaFechaProcesada === fecha) {
  throw new Error(`El BO del ${dd}/${mm}/${yyyy} ya fue procesado hoy. No se vuelve a ejecutar.`);
}

staticData.ultimaFechaProcesada = fecha;

return [{
  json: {
    fecha_hoy: fecha,
    url_listado: `https://www.boletinoficial.gob.ar/seccion/primera/${fecha}`
  }
}];

const item = $input.item.json;
let html = '';

if (typeof item === 'string') {
  html = item;
} else if (typeof item.data === 'string') {
  html = item.data;
} else {
  html = JSON.stringify(item);
}

if (html.length < 500) {
  throw new Error('HTML demasiado corto. Largo: ' + html.length);
}

const ORGANISMOS_RELEVANTES = [
  'AGENCIA DE RECAUDACIÓN Y CONTROL ADUANERO',
  'ADUANERO', 'ADUANA',
  'BANCO CENTRAL',
  'MINISTERIO DE ECONOMÍA',
  'HACIENDA', 'FINANZAS',
  'SECRETARÍA DE COMERCIO', 'COMERCIO INTERIOR', 'COMERCIO EXTERIOR',
  'ANSES', 'SEGURIDAD SOCIAL',
  'MINISTERIO DE TRABAJO', 'MINISTERIO DE CAPITAL HUMANO',
  'SUPERINTENDENCIA DE SEGUROS',
  'SUPERINTENDENCIA DE RIESGOS DEL TRABAJO', 'RIESGOS DEL TRABAJO',
  'COMISIÓN NACIONAL DE VALORES'
];

function extraerNormas(htmlInput, normasExistentes, vistas) {
  const linkRegex = /<a\s+href="(\/detalleAviso\/primera\/(\d+)\/(\d{8}))"[^>]*>([\s\S]*?)<\/a>/g;
  let match;

  while ((match = linkRegex.exec(htmlInput)) !== null) {
    const url = match[1];
    const id = match[2];
    const fecha = match[3];
    const contenido = match[4];

    if (vistas.has(id)) continue;

    const orgMatch = contenido.match(/<p class="item">([^<]{3,})<\/p>/);
    const organismo = orgMatch ? orgMatch[1].trim() : '';

    const esRelevante = ORGANISMOS_RELEVANTES.some(o =>
      organismo.toUpperCase().includes(o)
    );

    if (!esRelevante) continue;

    const smalls = [...contenido.matchAll(/<small>([^<]+)<\/small>/g)].map(m => m[1].trim());

    // Filtrar avisos oficiales genéricos (no tienen impacto fiscal)
    const tituloCorto = smalls[0] || '';
    if (tituloCorto === 'Aviso Oficial' || tituloCorto === '') continue;

    vistas.add(id);

    normasExistentes.push({
      json: {
        norma_id: id,
        fecha: fecha,
        organismo: organismo,
        titulo_corto: tituloCorto,
        descripcion: smalls[1] || '',
        url: `https://www.boletinoficial.gob.ar${url}`
      }
    });
  }
}

// Página 1: extraer del HTML inicial
const normas = [];
const vistas = new Set();
extraerNormas(html, normas, vistas);

// Extraer ultimoRubro del JavaScript de la página
const rubroMatch = html.match(/var\s+ultimoRubro\s*=\s*'([^']+)'/);
let ultimoRubro = rubroMatch ? rubroMatch[1] : '';

// Páginas 2 en adelante: usar la API de paginación
let hayMasDatos = true;
let pagina = 2;
const maxPaginas = 5;

while (hayMasDatos && pagina <= maxPaginas && ultimoRubro) {
  try {
    const apiUrl = `https://www.boletinoficial.gob.ar/seccion/actualizar/primera?pag=${pagina}&ult_rubro=${encodeURIComponent(ultimoRubro)}`;

    const response = await this.helpers.httpRequest({
      url: apiUrl,
      method: 'GET',
      json: true
    });

    if (response && response.html) {
      extraerNormas(response.html, normas, vistas);
    }

    hayMasDatos = response && response.hay_mas_datos === true;
    ultimoRubro = response && response.ult_rubro ? response.ult_rubro : '';
    pagina++;
  } catch (e) {
    break;
  }
}

if (normas.length === 0) {
  throw new Error('No se encontraron normas relevantes en ninguna página.');
}

return normas;

const html = $input.item.json.data;
const extractNode = $('Extraer Links').item.json;

const cuerpoMatch = html.match(/id="cuerpoDetalleAviso"[^>]*>([\s\S]*?)<\/div>\s*<\/div>\s*<\/div>/);

if (!cuerpoMatch) {
  return { json: { error: 'No se encontró el cuerpo', norma_id: extractNode.norma_id } };
}

let texto = cuerpoMatch[1]
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<img[^>]*>/gi, '')
  .replace(/<table[\s\S]*?<\/table>/gi, '[TABLA]')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#x27;/g, "'")
  .replace(/\s+/g, ' ')
  .trim();

if (texto.length > 6000) {
  texto = texto.substring(0, 6000) + '... [TEXTO TRUNCADO]';
}

return {
  json: {
    norma_id: extractNode.norma_id,
    fecha: extractNode.fecha,
    organismo: extractNode.organismo,
    titulo_corto: extractNode.titulo_corto,
    url: extractNode.url,
    texto_norma: texto
  }
};

const items = $input.all();
const metaItems = $('Extraer Links').all();

// Leer clientes desde Supabase
const SUPABASE_URL = 'https://imfruxezhadhpenkyhoo.supabase.co';
const SUPABASE_KEY = 'sb_publishable_vBOfVQzznPfSHqWhqarmdA_z6sF58sh';

const clientesRaw = await this.helpers.httpRequest({
  url: `${SUPABASE_URL}/rest/v1/Clientes RadarNorma?select=*`,
  method: 'GET',
  headers: {
    'apikey': SUPABASE_KEY,
    'Authorization': `Bearer ${SUPABASE_KEY}`
  },
  json: true
});

const clientes = clientesRaw.map(c => ({
  cuit: c.cuit,
  razon_social: c.razon_social,
  actividad: c.actividad,
  provincia: c.provincia,
  impuestos: c.impuestos.split(',').map(i => i.trim()),
  tipo: c.tipo,
  cierre: parseInt(c.cierre) || 12
}));

const normalizarImpuesto = (imp) => {
  const lower = imp.toLowerCase();
  if (lower.includes('ganancia')) return 'Ganancias';
  if (lower.includes('iva') || lower.includes('valor agregado')) return 'IVA';
  if (lower.includes('monotributo')) return 'Monotributo';
  if (lower.includes('bienes personales')) return 'Bienes Personales';
  if (lower.includes('ingresos brutos')) return 'IIBB';
  if (lower.includes('seguridad social') || lower.includes('previsional')) return 'Seguridad Social';
  if (lower.includes('sello')) return 'Sellos';
  if (lower.includes('aduana') || lower.includes('arancel') || lower.includes('importación') || lower.includes('exportación')) return 'Aduana';
  return imp;
};

const notificaciones = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const meta = metaItems[i] ? metaItems[i].json : {};

  let normaData;
  try {
    const llmText = item.json.output[0].content[0].text;
    normaData = JSON.parse(llmText);
  } catch (e) {
    continue;
  }

  if (normaData.importancia === 'nula' ||
      ((normaData.impuestos_afectados || []).length === 0 && 
       (normaData.importancia === 'baja' || normaData.importancia === 'media'))) {
    continue;
  }

  // Filtrar normas de casos específicos
  const resumenLower = (normaData.resumen || '').toLowerCase();
  if (resumenLower.includes('interpuesto por') || resumenLower.includes('presentado por') || resumenLower.includes('solicitado por')) {
    continue;
  }

  const clientesAfectados = [];

  for (const cliente of clientes) {
    let score = 0;
    const motivos = [];

    const impNormalizados = (normaData.impuestos_afectados || []).map(normalizarImpuesto);
    const impComunes = impNormalizados.filter(imp => cliente.impuestos.includes(imp));
    if (impComunes.length > 0) {
      score += 3;
      motivos.push(`Impuestos: ${impComunes.join(', ')}`);
    }

    const tipos = normaData.tipo_contribuyente || [];
    if (tipos.includes('todos')) {
      score += 2;
      motivos.push(`Tipo: ${cliente.tipo}`);
    } else if (tipos.includes(cliente.tipo)) {
      score += 2;
      motivos.push(`Tipo: ${cliente.tipo}`);
    } else if (tipos.length > 0) {
      continue; // La norma especifica tipos y este cliente no está incluido
    }

    const acts = normaData.actividades_afectadas || [];
    if (acts.length > 0) {
      const matchAct = acts.some(a =>
        cliente.actividad.toLowerCase().includes(a.toLowerCase())
      );
      if (matchAct) {
        score += 2;
        motivos.push('Actividad relacionada');
      }
    }

    const provs = normaData.provincias_afectadas || ['todas'];
    if (!provs.includes('todas')) {
      if (provs.includes(cliente.provincia)) {
        score += 1;
        motivos.push(`Provincia: ${cliente.provincia}`);
      } else {
        continue;
      }
    }

    // Filtro por cierre de ejercicio
    const cierreNorma = normaData.cierre_ejercicio_afectado;
    if (cierreNorma && cierreNorma !== 'todos') {
      const mesCierre = parseInt(cierreNorma);
      if (mesCierre && cliente.cierre !== mesCierre) {
        continue;
      }
    }

    if (score >= 4) {
      clientesAfectados.push({
        nombre: cliente.razon_social,
        cuit: cliente.cuit,
        motivos: motivos.join(' | ')
      });
    }
  }

  if (clientesAfectados.length > 0) {
    notificaciones.push({
      json: {
        norma_titulo: normaData.titulo || meta.titulo_corto || '',
        norma_numero: normaData.numero || '',
        norma_organismo: normaData.organismo || meta.organismo || '',
        norma_resumen: normaData.resumen || '',
        norma_importancia: normaData.importancia || '',
        norma_url: meta.url || '',
        accion_sugerida: normaData.accion_sugerida || '',
        vigencia: normaData.vigencia || 'no especificada',
        cantidad_clientes: clientesAfectados.length,
        clientes_afectados: clientesAfectados
      }
    });
  }
}

if (notificaciones.length === 0) {
  return [{ json: { sin_matches: true, mensaje: 'Ninguna norma de hoy afecta a clientes del estudio' } }];
}

return notificaciones;

const items = $input.all();
const mensajes = [];

for (const item of items) {
  const d = item.json;

  if (d.sin_matches) continue;

  let listaClientes = '';
  for (const c of d.clientes_afectados) {
    listaClientes += `• ${c.nombre} (${c.cuit})\n`;
  }

  const vigenciaTexto = d.vigencia ? `\n⏰ <b>Vigencia:</b> ${d.vigencia}` : '';

  const texto = `🔔 <b>RadarNorma — Nueva norma relevante</b>

📄 <b>${d.norma_titulo}</b>
🏛 ${d.norma_organismo}
📋 ${d.norma_numero}
⚡ Importancia: ${d.norma_importancia}${vigenciaTexto}

📝 <b>Resumen:</b>
${d.norma_resumen}

✅ <b>Acción sugerida:</b>
${d.accion_sugerida}

👥 <b>Clientes alcanzados (${d.cantidad_clientes}):</b>
${listaClientes}
🔗 <a href="${d.norma_url}">Ver norma completa</a>`;

  mensajes.push({ json: { mensaje_telegram: texto } });
}

if (mensajes.length === 0) {
  return [{ json: { mensaje_telegram: '✅ RadarNorma: No hay normas relevantes hoy.' } }];
}

return mensajes;
